<script lang="ts">import PortalHeader from '$lib/components/PortalHeader.svelte'; import { money } from '$lib/data'; import { Check, Circle, Clock3, Download, FileText, MessageCircle, ArrowUpRight } from 'lucide-svelte'; let{data}=$props();let selected=$state(data.orders[0]);const steps=$derived([['Files received','done'],['Work assigned','done'],['Editing in progress',selected.progress>30?'done':'current'],['Quality review',selected.status==='Waiting Review'?'current':selected.progress>=100?'done':''],['Ready for delivery',selected.status==='Ready Delivery'?'current':''],['Delivered',selected.status==='Completed'?'done':'']]);</script>
<svelte:head><title>{data.customer.business} — StudioFlow</title></svelte:head><PortalHeader label="Customer portal"/>
<main class="customer-main"><div class="hello"><p>Hello {data.customer.name.split(' ')[0]} 👋</p><h1>Your projects</h1><span>Track progress, invoices and deliveries in one place.</span></div>{#if data.orders.length>1}<div class="project-switch">{#each data.orders as order}<button class:active={selected.id===order.id} onclick={()=>selected=order}>{order.project}</button>{/each}</div>{/if}<section class="project-card card"><div class="project-head"><div><span>{selected.workType}</span><h2>{selected.project}</h2><p>{selected.id} · Delivery {selected.due}</p></div><span class="percent"><strong>{selected.progress}%</strong> complete</span></div><div class="customer-progress">{#each steps as step,i}<div class:done={step[1]==='done'} class:current={step[1]==='current'}><span>{#if step[1]==='done'}<Check size={13}/>{:else if step[1]==='current'}<Clock3 size={13}/>{:else}<Circle size={9}/>{/if}</span><strong>{step[0]}</strong>{#if i<steps.length-1}<i></i>{/if}</div>{/each}</div></section><div class="customer-grid"><section class="card invoice"><div class="section-title"><span><FileText size={16}/></span><div><h2>Invoice</h2><p>INV-{selected.id.slice(-4)}</p></div><button><Download size={13}/> Download</button></div><div class="money-grid"><div><span>Total</span><strong>{money(selected.price)}</strong></div><div><span>Paid</span><strong class="green">{money(selected.paid)}</strong></div><div><span>Balance</span><strong>{money(selected.price-selected.paid)}</strong></div></div></section><section class="card delivery"><div class="section-title"><span><Download size={16}/></span><div><h2>Project files</h2><p>{selected.status==='Ready Delivery'?'Your files are ready':'Available after final approval'}</p></div></div>{#if selected.status==='Ready Delivery'||selected.status==='Completed'}<a href={'https://'+selected.fileLink}>Download files <ArrowUpRight size={13}/></a>{:else}<span class="locked">Delivery link will appear here</span>{/if}</section></div><a class="whatsapp" href={'https://wa.me/'+data.customer.phone.replace(/\D/g,'')}><MessageCircle size={16}/> Chat with the studio on WhatsApp</a><p class="privacy">This private link shows only your projects, payments and approved progress updates.</p></main>
